const raw = $input.all()[0]?.json ?? {};
let payload = raw.query ?? raw;
let parseError = false;

if (typeof payload === "string") {
  try {
    payload = JSON.parse(payload);
  } catch (error) {
    payload = {};
    parseError = true;
  }
}

if (!payload || typeof payload !== "object" || Array.isArray(payload)) {
  payload = {};
  parseError = true;
}

let action = String(payload.action || payload.tool || payload.operation || "").trim();
if (!action) {
  const hasTargetUser = Boolean(payload.targetUserId || payload.allowedTargetUserId || payload.targetOpenId);
  action = hasTargetUser ? "read_okr" : (payload.chatId || payload.allowedChatId ? "list_chat_members" : "unknown");
}

const aliases = {
  read: "read_okr",
  get_okr: "read_okr",
  read_user_okr: "read_okr",
  list_members: "list_chat_members",
  list_chat_member: "list_chat_members",
  chat_members: "list_chat_members",
  group_members: "list_chat_members",
};
action = aliases[action] || action;

const supportedActions = ["read_okr", "list_chat_members"];
const maxMembersRaw = Number(payload.maxMembers ?? 20);
const maxMembers = Number.isFinite(maxMembersRaw) ? Math.min(Math.max(Math.trunc(maxMembersRaw), 1), 20) : 20;

return [{
  json: {
    action: supportedActions.includes(action) ? action : "unknown_action",
    requestedAction: action,
    supportedActions,
    parseError,
    targetUserId: payload.targetUserId || payload.allowedTargetUserId || payload.targetOpenId || "",
    targetUserIdType: payload.targetUserIdType || payload.allowedTargetUserIdType || "open_id",
    targetDisplayName: payload.targetDisplayName || payload.allowedTargetDisplayName || "目标用户",
    chatId: String(payload.chatId || payload.allowedChatId || "").trim(),
    chatDisplayName: payload.chatDisplayName || "当前群",
    maxMembers,
    pageSize: maxMembers,
    pageToken: String(payload.pageToken ?? payload.page_token ?? "").trim(),
  },
}];

const input = $input.all()[0]?.json ?? {};
const request = $('Normalize').all()[0]?.json ?? {};

function asBoolean(value) {
  if (typeof value === 'boolean') return value;
  if (typeof value === 'string') return value.toLowerCase() === 'true';
  return Boolean(value);
}

function finish(output, ok = false, extra = {}, errorCode = 'LIST_CHAT_MEMBERS_FAILED') {
  const members = Array.isArray(extra.members) ? extra.members : [];
  const hasMore = asBoolean(extra.hasMore ?? false);
  const nextPageToken = String(extra.nextPageToken ?? '').trim();
  return [{
    json: {
      ok,
      action: 'list_chat_members',
      data: { members, hasMore, nextPageToken },
      error: ok ? null : { code: errorCode, message: output, retryable: false },
      meta: {
        chatId: request.chatId || extra.chatId || '',
        chatDisplayName: request.chatDisplayName || extra.chatDisplayName || '',
        maxMembers: request.maxMembers || 20,
      },
      members,
      hasMore,
      nextPageToken,
      output,
      chatMemberToolOk: ok,
      ...extra,
    },
  }];
}

if (!request.chatId || request.parseError) {
  return finish('list_chat_members 缺少有效 chatId。请传入 {"chatId":"oc_xxx"}，或传入 query JSON 字符串。', false, {}, request.parseError ? 'INVALID_TOOL_INPUT' : 'MISSING_CHAT_ID');
}

if (input.error) {
  const detail = typeof input.error === 'string' ? input.error : (input.error.message || JSON.stringify(input.error));
  return finish('读取群成员失败：' + detail, false, {
    chatId: request.chatId,
    chatDisplayName: request.chatDisplayName,
  }, 'LIST_CHAT_MEMBERS_HTTP_ERROR');
}

if (input.code && input.code !== 0) {
  return finish('读取群成员失败：' + (input.msg || JSON.stringify(input)), false, {
    chatId: request.chatId,
    chatDisplayName: request.chatDisplayName,
  }, 'LIST_CHAT_MEMBERS_API_ERROR');
}

const rawMembers = input.items ?? input.members ?? input.data?.items ?? input.data?.members ?? [];
const hasMore = asBoolean(input.has_more ?? input.data?.has_more ?? input.hasMore ?? input.data?.hasMore);
const nextPageToken = String(input.page_token ?? input.data?.page_token ?? input.nextPageToken ?? input.data?.nextPageToken ?? '').trim();

if (!Array.isArray(rawMembers) || rawMembers.length === 0) {
  return finish('没有读取到群成员。请确认机器人在该群内，并且应用已开通 im:chat.members:read 权限。', false, {
    chatId: request.chatId,
    chatDisplayName: request.chatDisplayName,
    hasMore,
    nextPageToken,
  }, 'NO_CHAT_MEMBERS');
}

function memberId(member) {
  const id = member.member_id ?? member.open_id ?? member.user_id ?? member.id?.open_id ?? member.id?.user_id ?? '';
  return String(id || '').trim();
}

function memberName(member, id) {
  return String(member.name ?? member.display_name ?? member.member_name ?? member.nickname ?? id).trim();
}

const members = [];
const seen = new Set();
for (const member of rawMembers) {
  const id = memberId(member);
  if (!id || seen.has(id)) continue;
  const type = String(member.member_type ?? member.type ?? '').toLowerCase();
  if (type.includes('bot')) continue;
  seen.add(id);
  members.push({
    targetUserId: id,
    targetUserIdType: 'open_id',
    targetDisplayName: memberName(member, id),
  });
  if (members.length >= request.maxMembers) break;
}

const lines = [
  '已读取' + request.chatDisplayName + '成员 ' + members.length + ' 人。',
  hasMore ? '还有更多成员；下一页请继续传入 pageToken=' + nextPageToken + '。' : '',
  '接下来请逐个读取 members 数组中的用户 OKR。',
].filter(Boolean);

return finish(lines.join('\n'), true, {
  chatId: request.chatId,
  chatDisplayName: request.chatDisplayName,
  members,
  hasMore,
  nextPageToken,
});

const input = $input.all()[0]?.json ?? {};
const request = $('Normalize').all()[0]?.json ?? {};
const targetName = request.targetDisplayName || '目标用户';
const targetPossessive = targetName === '你' ? '你的' : targetName + '的';

function finish(output, ok = false) {
  return [{ json: { output, okrToolOk: ok, targetDisplayName: targetName } }];
}

if (!request.targetUserId || request.parseError) {
  return finish('read_okr 缺少有效 targetUserId。请传入目标用户 ID。');
}

if (input.error) {
  const detail = typeof input.error === 'string' ? input.error : (input.error.message || JSON.stringify(input.error));
  return finish('读取' + targetPossessive + ' OKR 周期失败：' + detail);
}

if (input.code && input.code !== 0) {
  return finish('读取' + targetPossessive + ' OKR 周期失败：' + (input.msg || JSON.stringify(input)));
}

const cycles = input.cycles ?? input.items ?? input.data?.cycles ?? input.data?.items ?? [];
if (!Array.isArray(cycles) || cycles.length === 0) {
  return finish('没有找到' + targetPossessive + ' OKR 周期。');
}

function asTime(value) {
  if (!value) return NaN;
  const raw = String(value).trim();
  const numeric = Number(raw);
  if (Number.isFinite(numeric)) return numeric < 1000000000000 ? numeric * 1000 : numeric;
  return new Date(raw.replace(' ', 'T')).getTime();
}

const now = Date.now();
const activeStatuses = new Set(['', '0', '1', 'default', 'normal']);
const invisibleStatuses = new Set(['2', '3', 'invalid', 'hidden']);
const statusValue = (cycle) => String(cycle.cycle_status ?? '').toLowerCase();
const currentCycles = cycles.filter((cycle) => {
  const start = asTime(cycle.start_time);
  const end = asTime(cycle.end_time);
  return Number.isFinite(start) && Number.isFinite(end) && start <= now && end >= now && activeStatuses.has(statusValue(cycle));
});
const visibleCycles = cycles.filter((cycle) => !invisibleStatuses.has(statusValue(cycle)));
const candidates = currentCycles.length ? currentCycles : (visibleCycles.length ? visibleCycles : cycles);
const selected = [...candidates].sort((a, b) => asTime(b.start_time) - asTime(a.start_time))[0];
const selectedId = String(selected?.id ?? '').trim();
if (!selectedId) {
  return finish('读取' + targetPossessive + ' OKR 周期失败：当前周期缺少 cycleId。');
}

function formatDate(value) {
  const time = asTime(value);
  if (!Number.isFinite(time)) return '';
  return new Intl.DateTimeFormat('zh-CN', { timeZone: 'Asia/Shanghai', year: 'numeric', month: '2-digit', day: '2-digit' }).format(new Date(time)).replace(/\//g, '-');
}

const start = formatDate(selected.start_time);
const end = formatDate(selected.end_time);

return [{
  json: {
    cycleId: selectedId,
    cycleLabel: start && end ? start + ' - ' + end : selectedId,
    targetUserIdType: request.targetUserIdType || 'open_id',
    targetDisplayName: targetName,
    okrToolOk: true,
  },
}];

const input = $input.all()[0]?.json ?? {};
const selected = $('Select cycle').all()[0]?.json ?? {};

if (!selected.okrToolOk) {
  return [{ json: { ...selected, noObjectives: true } }];
}

if (input.error) {
  const detail = typeof input.error === 'string' ? input.error : (input.error.message || JSON.stringify(input.error));
  return [{ json: { ...selected, noObjectives: true, output: '读取目标列表失败：' + detail } }];
}

if (input.code && input.code !== 0) {
  return [{ json: { ...selected, noObjectives: true, output: '读取目标列表失败：' + (input.msg || JSON.stringify(input)) } }];
}

const objectives = input.objectives ?? input.items ?? input.data?.objectives ?? input.data?.items ?? [];
if (!Array.isArray(objectives) || objectives.length === 0) {
  return [{ json: { ...selected, noObjectives: true, objectives: [] } }];
}

const expanded = objectives.map((objective) => ({
  json: {
    ...selected,
    objective,
    objectiveId: String(objective.id ?? '').trim(),
    noObjectives: false,
  },
}));

if (expanded.some((item) => !item.json.objectiveId)) {
  return [{ json: { ...selected, noObjectives: true, output: '读取目标列表失败：目标缺少 objectiveId。' } }];
}

return expanded;

const krResponses = $input.all();
const expanded = $('Expand objectives').all();
const firstExpanded = expanded[0]?.json ?? {};
const targetName = firstExpanded.targetDisplayName || '目标用户';
const targetPossessive = targetName === '你' ? '你的' : targetName + '的';

function finish(output, ok = false, extra = {}, errorCode = 'READ_OKR_FAILED') {
  return [{
    json: {
      ok,
      action: 'read_okr',
      data: extra.data || {},
      error: ok ? null : { code: errorCode, message: output, retryable: false },
      meta: {
        targetDisplayName: targetName,
        cycleId: firstExpanded.cycleId || '',
        cycleLabel: firstExpanded.cycleLabel || '',
      },
      output,
      okrToolOk: ok,
      targetDisplayName: targetName,
      cycleLabel: firstExpanded.cycleLabel,
      ...extra,
    },
  }];
}

if (firstExpanded.output && firstExpanded.noObjectives) {
  const code = firstExpanded.output.includes('缺少 objectiveId') ? 'MISSING_OBJECTIVE_ID' : 'READ_OKR_OBJECTIVES_FAILED';
  return finish(firstExpanded.output, false, {}, code);
}

if (firstExpanded.noObjectives) {
  return finish('读取结果：' + targetPossessive + ' ' + (firstExpanded.cycleLabel || '当前周期') + ' OKR\n这个周期下没有目标。', true, { data: { objectives: [] } });
}

function textFromContent(value) {
  if (!value) return '';
  if (typeof value === 'string') {
    const trimmed = value.trim();
    if (!trimmed) return '';
    try { return textFromContent(JSON.parse(trimmed)); } catch (error) { return trimmed; }
  }
  if (Array.isArray(value)) return value.map(textFromContent).filter(Boolean).join('');
  if (typeof value === 'object') {
    if (typeof value.text === 'string') return value.text.trim();
    if (typeof value.text_run?.text === 'string') return value.text_run.text.trim();
    if (typeof value.docs_link?.title === 'string') return value.docs_link.title.trim();
    if (Array.isArray(value.blocks)) return value.blocks.map(textFromContent).filter(Boolean).join('\n');
    if (Array.isArray(value.elements)) return value.elements.map(textFromContent).filter(Boolean).join('');
    if (value.paragraph?.elements) return textFromContent(value.paragraph.elements);
    if (value.content) return textFromContent(value.content);
  }
  return '';
}

function scoreText(score) {
  const numeric = Number(score);
  if (!Number.isFinite(numeric)) return '';
  const percent = numeric <= 1 ? Math.round(numeric * 100) : Math.round(numeric);
  return '（' + percent + '%）';
}

function objectiveLabel(expandedItem, index) {
  const objective = expandedItem.json.objective ?? {};
  const title = textFromContent(objective.content) || '(未命名目标)';
  return '第 ' + String(index + 1) + ' 个目标 ' + title;
}

for (const [index, expandedItem] of expanded.entries()) {
  const objective = expandedItem.json.objective;
  if (!objective) continue;
  const response = krResponses[index]?.json ?? {};
  const label = objectiveLabel(expandedItem, index);
  if (response.error) {
    const detail = typeof response.error === 'string' ? response.error : (response.error.message || JSON.stringify(response.error));
    const output = '读取' + targetPossessive + ' OKR 失败：' + label + ' 的关键结果读取失败：' + detail;
    return finish(output, false, { data: { failedObjectiveIndex: index + 1, failedObjectiveId: expandedItem.json.objectiveId || '', failedObjectiveTitle: textFromContent(objective.content) || '(未命名目标)' } }, 'READ_OKR_KEY_RESULTS_HTTP_ERROR');
  }
  const hasResponseCode = response.code !== undefined && response.code !== null && response.code !== '';
  const responseCode = Number(response.code);
  if (hasResponseCode && (!Number.isFinite(responseCode) || responseCode !== 0)) {
    const detail = response.msg || JSON.stringify(response);
    const output = '读取' + targetPossessive + ' OKR 失败：' + label + ' 的关键结果读取失败：' + detail;
    return finish(output, false, { data: { failedObjectiveIndex: index + 1, failedObjectiveId: expandedItem.json.objectiveId || '', failedObjectiveTitle: textFromContent(objective.content) || '(未命名目标)' } }, 'READ_OKR_KEY_RESULTS_API_ERROR');
  }
}

const lines = ['读取结果：' + targetPossessive + ' ' + (firstExpanded.cycleLabel || '当前周期') + ' OKR'];
for (const [index, expandedItem] of expanded.entries()) {
  const objective = expandedItem.json.objective;
  if (!objective) continue;
  lines.push(String(index + 1) + '. O: ' + (textFromContent(objective.content) || '(未命名目标)') + scoreText(objective.score));
  const response = krResponses[index]?.json ?? {};
  const keyResults = response.key_results ?? response.items ?? response.data?.key_results ?? response.data?.items ?? [];
  for (const kr of [...keyResults].sort((a, b) => Number(a.position ?? 0) - Number(b.position ?? 0))) {
    lines.push('   - KR: ' + (textFromContent(kr.content) || '(未命名关键结果)') + scoreText(kr.score));
  }
}

return finish(lines.join('\n'), true, { data: { objectiveCount: expanded.length } });

const input = $input.all()[0]?.json ?? {};
const request = $('Normalize').all()[0]?.json ?? {};
const targetName = request.targetDisplayName || input.targetDisplayName || '目标用户';
const targetPossessive = targetName === '你' ? '你的' : targetName + '的';

let code = 'MISSING_REQUIRED_FIELD';
let message = input.output || '';

if (request.parseError) {
  code = 'INVALID_TOOL_INPUT';
  message = 'okr_tools 参数不是有效 JSON。请传入 JSON 字符串。';
} else if (!request.targetUserId) {
  code = 'MISSING_TARGET_USER_ID';
  message = 'read_okr 缺少有效 targetUserId。请传入目标用户 ID。';
} else if (!input.cycleId) {
  code = input.output ? 'READ_OKR_CYCLE_FAILED' : 'MISSING_CYCLE_ID';
  message = input.output || '读取' + targetPossessive + ' OKR 失败：没有可用的 cycleId。';
} else if (!input.objectiveId) {
  code = 'MISSING_OBJECTIVE_ID';
  message = input.output || '读取' + targetPossessive + ' OKR 失败：目标缺少 objectiveId。';
}

return [{
  json: {
    ok: false,
    action: 'read_okr',
    output: message,
    error: { code, message, retryable: false },
    data: {},
    meta: {
      targetUserId: request.targetUserId || '',
      targetUserIdType: request.targetUserIdType || 'open_id',
      targetDisplayName: targetName,
      cycleId: input.cycleId || '',
      objectiveId: input.objectiveId || '',
    },
    okrToolOk: false,
    targetDisplayName: targetName,
    cycleLabel: input.cycleLabel || '',
  },
}];

const input = $input.all()[0]?.json ?? {};
const action = input.requestedAction || input.action || "";
const supported = Array.isArray(input.supportedActions) ? input.supportedActions.join(", ") : "read_okr, list_chat_members";
const output = input.parseError
  ? "okr_tools 参数不是有效 JSON。请传入 JSON 字符串。"
  : "okr_tools 不支持 action：" + (action || "(空)") + "。当前支持：" + supported;
return [{
  json: {
    ok: false,
    action: input.action || "unknown_action",
    output,
    error: {
      code: input.parseError ? "INVALID_TOOL_INPUT" : "UNKNOWN_ACTION",
      message: output,
      retryable: false,
    },
    data: {},
    meta: { supportedActions: input.supportedActions || [] },
  },
}];
